final:
module RefModule (
    input [3:0] d,
    input clk,
    input load,
    output [3:0] q
);

    reg [3:0] q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load) begin
            q_reg <= d;
        end
    end

    assign q = q_reg;

endmodule
